import httpx
import json
from typing_extensions import TypedDict
from langgraph.graph import StateGraph, END


class A2AState(TypedDict):
    question: str
    agent_url: str
    answer: str
    status: str


def discover_agent(state: A2AState) -> dict:
    """Fetch AgentCard to confirm the agent supports text research."""
    with httpx.Client() as client:
        card = client.get(f"{state['agent_url']}/.well-known/agent.json").json()
    skill_ids = [s["id"] for s in card.get("skills", [])]
    if "research" not in skill_ids:
        return {"status": "unsupported"}
    return {"status": "discovered"}


def submit_and_stream(state: A2AState) -> dict:
    """POST a task and consume the SSE stream to retrieve the answer."""
    task_payload = {
        "sessionId": "session-001",
        "history": [
            {"role": "user", "parts": [{"type": "text", "text": state["question"]}]}
        ],
    }
    base = state["agent_url"]
    with httpx.Client(timeout=60) as client:
        task = client.post(f"{base}/tasks", json=task_payload).json()
        task_id = task["id"]

        answer = ""
        with client.stream("POST", f"{base}/tasks/{task_id}/stream",
                           json=task_payload) as resp:
            for line in resp.iter_lines():
                if not line.startswith("data: "):
                    continue
                event = json.loads(line[6:])
                if "artifact" in event:
                    for part in event["artifact"].get("parts", []):
                        if part.get("type") == "text":
                            answer += part["text"]
                if event.get("final"):
                    break

    return {"answer": answer, "status": "completed"}


builder = StateGraph(A2AState)
builder.add_node("discover", discover_agent)
builder.add_node("call", submit_and_stream)
builder.set_entry_point("discover")
builder.add_conditional_edges(
    "discover",
    lambda s: "call" if s["status"] == "discovered" else END,
    {"call": "call", END: END},
)
builder.add_edge("call", END)
graph = builder.compile()

result = graph.invoke({
    "question": "What is the A2A protocol?",
    "agent_url": "http://localhost:8000",
    "answer": "", "status": "",
})
print(result["answer"])

