def handle_sse_stream(base: str, task_id: str, human_input_fn):
    with httpx.Client(timeout=120) as client:
        with client.stream("POST", f"{base}/tasks/{task_id}/stream", json={}) as r:
            for line in r.iter_lines():
                if not line.startswith("data: "):
                    continue
                event = json.loads(line[6:])
                state = event.get("status", {}).get("state")
                if state == "input-needed":
                    question = (
                        event["status"]["message"]["parts"][0]["text"]
                    )
                    user_answer = human_input_fn(question)
                    # resume by posting the answer
                    client.post(f"{base}/tasks/{task_id}/messages", json={
                        "role": "user",
                        "parts": [{"type": "text", "text": user_answer}],
                    })
                if event.get("final"):
                    break

import httpx


def build_authenticated_client(agent_url: str, bearer_token: str) -> httpx.Client:
    """Create an httpx client that injects the bearer token on every request."""
    return httpx.Client(
        base_url=agent_url,
        headers={"Authorization": f"Bearer {bearer_token}"},
        timeout=60,
    )


def discover_and_verify_auth(agent_url: str) -> dict:
    """Fetch AgentCard and check what auth is required."""
    with httpx.Client() as c:
        card = c.get(f"{agent_url}/.well-known/agent.json").json()
    auth = card.get("authentication", {"schemes": ["none"]})
    schemes = auth.get("schemes", [])
    return {"card": card, "auth_schemes": schemes}


