from fastapi import FastAPI, Request, Header
from typing import Optional

webhook_app = FastAPI()

@webhook_app.post("/webhooks/a2a")
async def receive_push(request: Request, x_a2a_token: Optional[str] = Header(None)):
    if x_a2a_token != "webhook-secret-abc123":
        return {"error": "unauthorised"}, 401
    event = await request.json()
    state = event.get("status", {}).get("state")
    print(f"Task {event['id']} → {state}")
    if event.get("final"):
        # trigger downstream processing
        pass
    return {"ok": True}
